where.if:
and exists (
    select 1 from edu_course_enrollment e
    where e.course_id = c.course_id
    and e.parent_user_id = #{params.currentUserId}

        and e.student_user_id = #{params.targetStudentUserId}

)

choose.when:
and exists (
    select 1 from edu_course_enrollment e
    where e.course_id = c.course_id
    and e.parent_user_id = #{params.currentUserId}

        and e.student_user_id = #{params.targetStudentUserId}

    and e.status = '0'
)

and not exists (
    select 1 from edu_course_enrollment e
    where e.course_id = c.course_id
    and e.parent_user_id = #{params.currentUserId}

        and e.student_user_id = #{params.targetStudentUserId}

    and e.status = '0'
)

mapper.update:
update edu_course
course_name = #{courseName}, course_code = #{courseCode}, category = #{category}, grade_scope = #{gradeScope}, teacher_name = #{teacherName}, campus = #{campus}, week_day = #{weekDay}, start_time = #{startTime}, end_time = #{endTime}, start_date = #{startDate}, end_date = #{endDate}, max_capacity = #{maxCapacity}, current_capacity = #{currentCapacity}, status = #{status}, description = #{description}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where course_id = #{courseId}
